(window.webpackJsonp=window.webpackJsonp||[]).push([[100],{727:function(n,r){n.exports='\x3c!-- \r\ntitle: 07-常用输入模块\r\nsort: \r\n--\x3e \r\n## 旋转编码器\r\n\r\n### 接线图\r\n\r\n![img](https://www.arduino.cn/data/attachment/forum/201909/18/182520dg1o4aidzyg6dzz1.jpg)\r\n\r\n### 实例\r\n\r\n```c\r\nint CLK = 2;\r\nint DT = 3;\r\nint SW = 4;\r\nconst int interrupt0 = 0;\r\nint count = 0;\r\nint lastCLK = 0;\r\n\r\nvoid setup()\r\n{\r\n  pinMode(SW, INPUT);\r\n  digitalWrite(SW, HIGH);\r\n  pinMode(CLK, INPUT);\r\n  pinMode(DT, INPUT);\r\n  attachInterrupt(interrupt0, ClockChanged, FALLING);\r\n  // 中断函数\r\n  Serial.begin(9600);\r\n}\r\n\r\nvoid loop()\r\n{\r\n  if (!digitalRead(SW) && count != 0)\r\n  {\r\n    count = 0;\r\n    Serial.print("count:");\r\n    Serial.println(count);\r\n  }\r\n}\r\n\r\nvoid ClockChanged()\r\n{\r\n\r\n  int clkValue = digitalRead(CLK);\r\n  int dtValue = digitalRead(DT);\r\n  if (lastCLK != clkValue)\r\n  {\r\n    lastCLK = clkValue;\r\n    count += (clkValue != dtValue ? 1 : -1);\r\n    Serial.print("count:");\r\n    Serial.println(count);\r\n  }\r\n\r\n}\r\n```\r\n\r\n'}}]);